SELECT COUNT(1)
FROM sys_user
WHERE phone = #{phone}
  AND id != #{excludeId}

SELECT COUNT(1)
FROM sys_user
WHERE email = #{email}
  AND id != #{excludeId}

mapper.update:
UPDATE sys_user
SET password_hash = #{passwordHash},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE sys_user
SET status = #{status},
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT
FROM sys_user u LEFT JOIN sys_role r ON u.role_id = r.id
ORDER BY u.id DESC LIMIT #{pageSize} OFFSET #{offset}
